#include <stack>
#include <sstream>
#include <string>

using namespace std;

string evaluatePostfix(const string& expr) {
    stack<int> st;
    istringstream iss(expr);
    string token;
    while (iss >> token) {
        if (token == "+" || token == "-" || token == "*" || token == "/") {
            if (st.size() < 2) {
                return "error: insufficient operands";
            }
            int b = st.top(); st.pop();
            int a = st.top(); st.pop();
            if (token == "+") st.push(a + b);
            else if (token == "-") st.push(a - b);
            else if (token == "*") st.push(a * b);
            else if (token == "/") {
                if (b == 0) return "error: division by zero";
                st.push(a / b);
            }
        } else {
            istringstream tokenStream(token);
            int num;
            char remaining;
            if (!(tokenStream >> num) || tokenStream >> remaining) {
                return "error: invalid symbol";
            }
            st.push(num);
        }
    }
    if (st.size() != 1) return "error: invalid expression";
    return to_string(st.top());
}
