type TaskManager struct {
	tasks *list.List
}

func NewTaskManager() *TaskManager {
	return &TaskManager{
		tasks: list.New(),
	}
}

func (tm *TaskManager) InsertTask(taskID, taskName string, priority int) {
	newTask := &Task{ID: taskID, Name: taskName, Priority: priority}
	element := tm.tasks.Front()
	for i := 0; i < priority; i++ {
		if element == nil {
			tm.tasks.PushBack(newTask)
			return
		}
		element = element.Next()
	}
	if element != nil {
		tm.tasks.InsertBefore(newTask, element)
	} else {
		tm.tasks.PushBack(newTask)
	}
}

func (tm *TaskManager) RemoveTask(index int) {
	if index < 0 || index >= tm.tasks.Len() {
		return
	}
	element := tm.tasks.Front()
	for i := 0; i < index; i++ {
		element = element.Next()
	}
	tm.tasks.Remove(element)
}
