import java.util.HashMap;
import java.util.Map;

public class MaxNonConsecutiveSum {
    public int maxSum(int[] nums) {
        Map<Integer, Integer> memo = new HashMap<>();
        return calculateMaxSum(nums, nums.length - 1, memo);
    }

    private int calculateMaxSum(int[] nums, int index, Map<Integer, Integer> memo) {
        if (index < 0) return 0;
        if (memo.containsKey(index)) return memo.get(index);
        int include = nums[index] + calculateMaxSum(nums, index - 2, memo);
        int exclude = calculateMaxSum(nums, index - 1, memo);
        int result = Math.max(include, exclude);
        memo.put(index, result);
        return result;
    }
}
