import java.util.*;

public class SocialNetwork {
    private HashMap<String, Set<String>> followersMap = new HashMap<>();
    private List<FollowEvent> followEvents = new ArrayList<>();

    private static class FollowEvent {
        String follower;
        String followed;

        FollowEvent(String follower, String followed) {
            this.follower = follower;
            this.followed = followed;
        }
    }

    public void follow(String follower, String followed) {
        Set<String> followers = followersMap.get(followed);
        if (followers == null) {
            followers = new HashSet<>();
            followersMap.put(followed, followers);
        }
        followers.add(follower);
        followEvents.add(new FollowEvent(follower, followed));
    }

    public String findLatestCommonFollower(String userA, String userB) {
        for (int i = followEvents.size() - 1; i >= 0; i--) {
            FollowEvent event = followEvents.get(i);
            if (event.followed.equals(userA) || event.followed.equals(userB)) {
                String follower = event.follower;
                if (followersMap.getOrDefault(userA, Collections.emptySet()).contains(follower)
                        && followersMap.getOrDefault(userB, Collections.emptySet()).contains(follower)) {
                    return follower;
                }
            }
        }
        return null;
    }

    public List<String> suggestFriends(String user) {
        Set<String> userFollowers = followersMap.getOrDefault(user, Collections.emptySet());
        HashMap<String, Integer> mutualCounts = new HashMap<>();

        for (String follower : userFollowers) {
            Set<String> followed = followersMap.get(follower);
            if (followed == null) continue;
            for (String candidate : followed) {
                if (candidate.equals(user) || userFollowers.contains(candidate)) continue;
                mutualCounts.put(candidate, mutualCounts.getOrDefault(candidate, 0) + 1);
            }
        }

        List<String> suggestions = new ArrayList<>(mutualCounts.keySet());
        Collections.sort(suggestions, (a, b) -> {
            int cmp = mutualCounts.get(b).compareTo(mutualCounts.get(a));
            return cmp != 0 ? cmp : a.compareTo(b);
        });

        return suggestions;
    }
}
