use std::collections::BTreeMap;

#[derive(Debug)]
pub struct Student {
    pub name: String,
    pub age: u32,
}

pub struct StudentRoster {
    students: BTreeMap<u32, Student>,
}

impl StudentRoster {
    pub fn new() -> Self {
        StudentRoster {
            students: BTreeMap::new(),
        }
    }

    pub fn add_student(&mut self, id: u32, name: String, age: u32) {
        self.students.insert(id, Student { name, age });
    }

    pub fn remove_student(&mut self, id: u32) -> Result<(), String> {
        if self.students.remove(&id).is_none() {
            Err(format!("Student ID {} not found", id))
        } else {
            Ok(())
        }
    }
}
