package main

type PageDetails struct {
	Content string
}

type Cache struct {
	pages map[string]PageDetails
}

func NewCache() *Cache {
	return &Cache{
		pages: make(map[string]PageDetails),
	}
}

func (c *Cache) AddPage(id string, details PageDetails) {
	c.pages[id] = details
}

func (c *Cache) GetPage(id string) (PageDetails, bool) {
	details, exists := c.pages[id]
	return details, exists
}

func (c *Cache) DeletePage(id string) {
	delete(c.pages, id)
}
